Actionscript.script:
import NGIO;

// clear out any onComplete handler when this unloads
var _this = this;
NGIO.connectorComponent = this;
this.dispose = function() {
	NGIO.connectorComponent = null;
	_this.onComplete = null;
}

this.onUnload = this.dispose;

// some of our handler functions can use ngConnector to reference this clip
var ngConnector:MovieClip = this;

// stop the parent timeline from playing until this is done
_parent.stop();

// Just go to the error screen if the component doesn't have an app id
if (!this.appId) {
	trace("Newgrounds.IO Connector Error: Missing required App ID");
	gotoAndStop('session_error');
} else {
	if (getBytesLoaded() >= getBytesTotal()) {
		gotoAndStop('init_api');
	} else {
		loadBar.onEnterFrame = function():Void {
			var loaded:Number = Math.round((getBytesLoaded() / getBytesTotal()) * 100);
			this._xscale = loaded;
			if (loaded >= 100) {
				this.onEnterFrame = null;
				this._parent._parent.gotoAndStop('init_api');
			}
		};
	}
}

stop();

import NGIO;

// initialize the NGIO wrapper
NGIO.init(this.appId, this.encryptionKey, this.appVersion, this.debug);

if (this.showNetworkiMessages) NGIO.core.debugNetworkCalls = true;

// Load information about the latest version of this app, and verify that the website hosting it has permission
NGIO.loadAppData(
	// this is the data we are pulling...
	[
		'currentVersion',
		'hostApproved'
	],

	// and we'll handle the results here when the server responds
	function (result) {

		// if this host doesn't have permission, jump to the frame that will let the player find a legal copy
		if (!NGIO.getHostApproved()) {
			this.gotoAndStop('blocked_host');

		// if there's a newer version of this app available, jump to the frame that will help the user find it
		} else if (NGIO.getClientDeprecated() === true) {
			this.gotoAndStop('client_deprecated');

		// if everything checks out, let's move on to verifying the user session
		} else {
			this.gotoAndStop('check_session');

		}

	},

	// this tells the above function to use this clip as the 'this' context
	this
);

stop();

import io.newgrounds.SessionStatus;

/**
 * Check the initial session.  One of 3 things will happen here (unless there's an error)
 *  1) This is a new user. We'll pull a guest session from the server and prompt them to log in
 *  2) The user has a saved session. We'll welcome them back and give an option to change users.
 *  3) The newgrounds website passed a pre-authenticated session. We can just start the game.
 *
 *  If the user had a saved session that expired, they will just be treated like a new user.
 */
NGIO.checkSession(

	/* figure out what to do based on the session status */
	function(sessionStatus) {

		switch(sessionStatus.status) {

			// The user had an existing session, and they are logged in!
			case SessionStatus.LOGGED_IN:

				// now we need to determine how they got validated...

				if (NGIO.core.appState.session.isPreauthenticated()) {

					// This is a game running directly in Newgrounds, we can just start the game!
					this.gotoAndStop('ng_direct_session');

				} else {

					// This is a saved session. Have the user verify they want to use this login still
					this.gotoAndStop('verify_user');
				}
				break;

			// This is a new user.  We have a guest session, but they still need to log in
			case SessionStatus.NOT_LOGGED_IN:

				// go to the frame asking the user if they want to sign in
				this.gotoAndStop('login_required');
				break;

			// If we get any other responses, something went wrong
			default:
				this.gotoAndStop('session_error');
				break;
		}
	},
	this
);

// This game is being hosted directly on NG, and the user is logged in.
// Let's just load any feature data we may need and start the game without further interruptions
NGIO.loadAppData(

	// we will pull all the meta data for the following features...
	[
	 	'saveSlots',
		'medals',
		'medalScore',
		'scoreBoards'
	],

	// go to the frame that starts the main game
	function() {
		this.gotoAndPlay('finished');
	},

	this
);

stop();

// We're waiting for the user to finish logging in.
import io.newgrounds.SessionStatus;

// This will check the status of the current user session and determine what to do next
this.onCheckSession = function(sessionStatus):Void {

    // if the session is ready to go, jump to the frame that welcomes the user
    if (sessionStatus.status == SessionStatus.LOGGED_IN) {
        this.gotoAndStop('welcome_user');

	// if the user cancelled the login, go to the cancelled message
	} else if (sessionStatus.status == SessionStatus.LOGIN_CANCELLED) {
        this.gotoAndStop('login_cancelled');

    // if we're still in the waiting state, wait 2 seconds, then pull the session data from the server again
    } else if (sessionStatus.status == SessionStatus.WAITING_FOR_PASSPORT) {

        var _timerId:Number = setInterval(function():Void {
            clearInterval(_timerId);
            // pull the latest session data and call this handler function again
            NGIO.checkSession(ngConnector.onCheckSession, ngConnector);
        }, 2000);

    // in any other case, something went wrong, or the user hit the cancel button.
    // just go to the error frame so they can choose to try again if they want
    } else {
        this.gotoAndStop('session_error');
    }
}

// load the latest session state form the server and handle it in the above function
NGIO.checkSession(this.onCheckSession, this);

// if we're stuck in this waiting screen (probably because the user closed the login window too early)
// clicking the cancel button will kill the current session then go back to the login prompt so
// the user can try again, or decline logging in
cancel_login_btn.onRelease = function() {
    ngConnector.gotoAndStop('sign_out');
};

stop();

// the user wants to log out, or we have a bad session and we need to clear it out

// Tells the server to end the current session, then run the handler funcion
NGIO.endSession(
	function() {

		// we can just go back to the check session frame wich will give us the chance to log in again
		this.gotoAndStop('check_session');
	},
	this
);
stop();

// Something went wrong here.  Let the user try again or just play without a login

login_again_yes_btn.onRelease = function() {
	// treat this as a sign out so we can start everything again
	ngConnector.gotoAndStop('check_session');
};


login_again_no_btn.onRelease = function() {
	// start the game without logging in
	ngConnector.gotoAndStop('finished');
};

stop();

// This frame handles when a user finishes logging in.  Show a quick welcome message then start the game

// update the welcome text so the user can see their name and know they got in okay
welcome.text = "Welcome " + NGIO.getUser().name;

// we'll show the login message for 1.5 seconds
var _timerId:Number = setInterval(function():Void {
    clearInterval(_timerId);
    // go to the frame that will start the main game
    ngConnector.gotoAndPlay('finished');
}, 1500);

// While we are on this screen, we can load all the meta data for the different API objects
NGIO.loadAppData(
    [
        'saveSlots',
        'medals',
        'medalScore',
        'scoreBoards'
    ]
);

stop();

// This frame handles when the user is logged in via a saved session.
// We give them the option to log out, or play the game as the current user

// show a welcome message so they know what account they logged in with
welcome.text = "Signed in as "+NGIO.getUser().name;

// We can also go ahead and load all the meta data for the different API objects while we're waiting
NGIO.loadAppData(
	[
	 	'saveSlots',
		'medals',
		'medalScore',
		'scoreBoards'
	]
);

continue_as_user_btn.onRelease = function() {
	// start the game
	ngConnector.gotoAndPlay('finished');
};


sign_out_btn.onRelease = function() {
	// end the current session, and go back to the main login prompt
	ngConnector.gotoAndStop('sign_out');
};

stop();

// We have a guest session, ask the user to log in.

login_yes_btn.onRelease = function() {
	// this will open the Newgrounds Passport window in a new browser tab so the user can log in
	NGIO.openPassport();

	// we'll also go to the waiting frame wich will check the server in a loop to see if the login is ready yet
	ngConnector.gotoAndStop('waiting_for_user');
};


login_no_btn.onRelease = function() {
	// start the game without logging in
	ngConnector.gotoAndStop('finished');
};

stop();

// Something went wrong here.  Let the user try again or just play without a login

try_again_yes_btn.onRelease = function() {
	// treat this as a sign out so we can start everything again
	ngConnector.gotoAndStop('sign_out');
};


try_again_no_btn.onRelease = function() {
	// start the game without logging in
	ngConnector.gotoAndStop('finished');
};

stop();

// A new version of this game is available, ask the user if they want to play it instead.

new_version_yes_btn.onRelease = function() {
	// load the latest version
	NGIO.openOfficialUrl();
};


new_version_no_btn.onRelease = function() {
	// the user wants to keep using this version, see if they are logged in
	ngConnector.gotoAndStop('check_session');
};

stop();

// The site hosting this game has been blocked. Help the user find a legal copy

legal_version_btn.onRelease = function() {
	// load the legal version
	NGIO.openOfficialUrl();
};

stop();
